"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[775],{8551:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"defaultSidebar":[{"type":"link","label":"Where to Go From Here","href":"/Resonix/docs/intro","docId":"intro","unlisted":false},{"type":"link","label":"Getting Started","href":"/Resonix/docs/documentation","docId":"documentation","unlisted":false},{"type":"category","label":"Guides","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"The Polling Gap","href":"/Resonix/docs/guides/why-bullets-miss","docId":"guides/why-bullets-miss","unlisted":false},{"type":"link","label":"How Sound Propagates","href":"/Resonix/docs/guides/physics-features","docId":"guides/physics-features","unlisted":false},{"type":"link","label":"Networking and Trust","href":"/Resonix/docs/guides/networking","docId":"guides/networking","unlisted":false},{"type":"link","label":"Performance","href":"/Resonix/docs/guides/performance","docId":"guides/performance","unlisted":false},{"type":"link","label":"Benchmarks","href":"/Resonix/docs/guides/benchmarks","docId":"guides/benchmarks","unlisted":false}]},{"type":"link","label":"FAQ","href":"/Resonix/docs/faq","docId":"faq","unlisted":false},{"type":"link","label":"Credits","href":"/Resonix/docs/credits","docId":"credits","unlisted":false}]},"docs":{"credits":{"id":"credits","title":"Credits","description":"Resonix is built and maintained by VeDevelopment.","sidebar":"defaultSidebar"},"documentation":{"id":"documentation","title":"Sound Travels Where Physics Says It Should","description":"Resonix is an acoustic simulation engine for Roblox. It answers one question: how much of a sound actually reaches a listener? Not just whether they\'re in range \u2014 how much of it arrives after travelling through walls, floors, and the air between them.","sidebar":"defaultSidebar"},"faq":{"id":"faq","title":"FAQ","description":"Answers to the questions that come up most often.","sidebar":"defaultSidebar"},"guides/benchmarks":{"id":"guides/benchmarks","title":"Benchmarks","description":"This page covers how to profile Resonix in your own project and what numbers to look for.","sidebar":"defaultSidebar"},"guides/networking":{"id":"guides/networking","title":"Networking and Trust","description":"Multiplayer acoustic simulation has the same fundamental problem as any client-authoritative system: the client can lie.","sidebar":"defaultSidebar"},"guides/performance":{"id":"guides/performance","title":"Performance","description":"A single audibility query costs almost nothing. A query loop running 40 listeners every 0.1 seconds, each querying against 60 active emissions in a dense map \u2014 that adds up.","sidebar":"defaultSidebar"},"guides/physics-features":{"id":"guides/physics-features","title":"How Sound Propagates","description":"There\'s a version of sound detection that technically works \u2014 any listener within a radius detects any sound, regardless of what\'s between them and the source \u2014 but doesn\'t feel right. A gunshot behind three concrete walls reads the same as one fired in an open field. A crouching player\'s footstep is just as detectable as a sprint at the same distance. Detection feels arbitrary in ways that feel unfair.","sidebar":"defaultSidebar"},"guides/why-bullets-miss":{"id":"guides/why-bullets-miss","title":"The Polling Gap","description":"You fire a gunshot. No reaction. You fire another \u2014 it reacts immediately. A third \u2014 nothing again.","sidebar":"defaultSidebar"},"intro":{"id":"intro","title":"Where to Go From Here","description":"Resonix has a few distinct layers. This page is a map.","sidebar":"defaultSidebar"}}}}')}}]);